const materias = new Set();

for (const item of $input.all()) {
  const texto = item.json.especialidad_materias;
  if (!texto) continue;
  for (const materia of texto.split(',').map(m => m.trim()).filter(Boolean)) {
    materias.add(materia);
  }
}

const lista = Array.from(materias);
let mensaje = "\ud83d\udcda Selecciona una materia:\n\n";
lista.forEach((materia, i) => { mensaje += `${i + 1}\ufe0f\u20e3 ${materia}\n`; });
mensaje += "\nEscribe el numero de la materia.";

return [{
  json: {
    mensaje,
    materias_json: JSON.stringify(lista)
  }
}];

const opcionTexto = $('Preparar Datos Entrada').first().json.mensaje;
const opcion = Number(opcionTexto);

const sesion = $('Router Paso').first().json;
let materias = [];
try { materias = JSON.parse(sesion.datos_parciales || '[]'); } catch (e) { materias = []; }

if (!opcion || opcion < 1 || opcion > materias.length) {
  return [{
    json: {
      valido: false,
      telegram_user: sesion.telegram_user,
      mensaje_error: "Opcion invalida. Escribe el numero de una materia de la lista."
    }
  }];
}

return [{
  json: {
    valido: true,
    telegram_user: sesion.telegram_user,
    materia_elegida: materias[opcion - 1]
  }
}];

const texto = ($('Preparar Datos Entrada').first().json.mensaje || '').trim();
const sesion = $('Router Paso').first().json;

// Formato exigido por especificacion: AAAA-MM-DD (YYYY-MM-DD)
const regex = /^(\d{4})-(\d{2})-(\d{2})$/;
const match = texto.match(regex);

let valido = false;
let motivo = '';
let fechaISO = null;

if (!match) {
  motivo = 'Formato invalido. Usa AAAA-MM-DD, ejemplo: 2026-08-15.';
} else {
  const anio = Number(match[1]);
  const mes = Number(match[2]);
  const dia = Number(match[3]);
  const fecha = new Date(anio, mes - 1, dia);
  const esFechaReal = fecha.getFullYear() === anio && fecha.getMonth() === mes - 1 && fecha.getDate() === dia;

  const hoy = new Date();
  hoy.setHours(0, 0, 0, 0);

  if (!esFechaReal) {
    motivo = 'Esa fecha no existe en el calendario. Verifica el dia y el mes.';
  } else if (fecha < hoy) {
    motivo = 'La fecha no puede ser anterior a hoy.';
  } else {
    valido = true;
    fechaISO = `${anio}-${String(mes).padStart(2, '0')}-${String(dia).padStart(2, '0')}`;
  }
}

let datos = {};
try { datos = JSON.parse(sesion.datos_parciales || '{}'); } catch (e) { datos = {}; }

return [{
  json: {
    valido,
    motivo,
    telegram_user: sesion.telegram_user,
    materia: datos.materia || null,
    fecha_texto: texto,
    fecha_iso: fechaISO
  }
}];

const miUsuario = $('Preparar Datos Entrada').first().json.telegram_user;
const mensaje = ($('Preparar Datos Entrada').first().json.mensaje || '').trim().toLowerCase();

// Comandos globales: sin importar en que paso este el usuario, estos mensajes
// interrumpen el flujo actual y lo mandan a una pantalla especifica.
const esComandoInicio = mensaje === 'inicio' || mensaje === '/inicio' || mensaje === '/start';
const esComandoConsultar = mensaje === 'consultar' || mensaje === 'mis tutorias' || mensaje === '/consultar';
const esComandoCancelar = mensaje === 'cancelar' || mensaje === '/cancelar';

let pasoForzado = null;
if (esComandoInicio) pasoForzado = 'menu';
else if (esComandoConsultar) pasoForzado = 'consultando';
else if (esComandoCancelar) pasoForzado = 'cancelando';

const todas = $input.all();
// Línea corregida para soportar listas vacías sin romper el flujo:
const miSesion = todas.find(item => item && item.json && String(item.json.telegram_user) === String(miUsuario));

if (miSesion) {
  return [{
    json: {
      existe: true,
      telegram_user: miUsuario,
      pantalla_actual: pasoForzado ? 'inicio' : miSesion.json.pantalla_actual,
      paso_actual: pasoForzado ? pasoForzado : miSesion.json.paso_actual,
      datos_parciales: pasoForzado ? '{}' : (miSesion.json.datos_parciales || '{}')
    }
  }];
}

return [{
  json: {
    existe: false,
    telegram_user: miUsuario,
    pantalla_actual: 'inicio',
    paso_actual: pasoForzado ? pasoForzado : 'menu',
    datos_parciales: '{}'
  }
}];

const datos = $('Validar Fecha').first().json;
const fecha = datos.fecha_iso; // 'YYYY-MM-DD'
const [anio, mes, dia] = fecha.split('-').map(Number);
const fechaObj = new Date(anio, mes - 1, dia);
const dias = ['Domingo','Lunes','Martes','Miercoles','Jueves','Viernes','Sabado'];
const dia_semana = dias[fechaObj.getDay()];

return [{
  json: {
    telegram_user: datos.telegram_user,
    chat_id: datos.telegram_user,
    materia: datos.materia,
    fecha: fecha,
    dia_semana
  }
}];

// 1. Recuperamos los datos de la solicitud (materia, fecha, dia_semana, id_tutoria)
const sesion = { ...$('Preparar Datos Busqueda').first().json, id_tutoria: $('Registrar Solicitud (Solicitada)').first().json.id_tutoria };

// 2. Filtramos tutores: que estén Activos y que den la materia pedida
const tutores = $('Leer Tutores').all().map(i => i.json)
  .filter(t => t.estado === 'Activo' && (t.especialidad_materias || '').includes(sesion.materia));

// 3. Tomamos TODA la disponibilidad que llega de forma segura
const todasLasEntradas = $input.all();
const disponibilidad = (todasLasEntradas && todasLasEntradas.length > 0) ? todasLasEntradas.map(i => i.json) : [];

// 4. De los tutores filtrados, sacamos solo sus ids
const tutorIds = tutores.map(t => t.id_tutor);

// 5. Buscamos un slot de disponibilidad que sea de uno de esos tutores, ese día, y que esté Libre
const libre = disponibilidad.find(d =>
  d && 
  tutorIds.includes(d.id_tutor) &&
  d.dia_semana === sesion.dia_semana &&
  d.estado === 'Libre'
);

// 6. Si encontramos un slot libre, buscamos los datos completos de ese tutor
const tutor = libre ? tutores.find(t => t.id_tutor === libre.id_tutor) : null;

// 7. Devolvemos un solo objeto con todo lo que necesitan los siguientes nodos
return [{
  json: {
    ...sesion,
    encontrado: !!libre,
    id_dispo: libre ? libre.id_dispo : null,
    hora_inicio: libre ? libre.hora_inicio : null,
    tutor_nombre: tutor ? tutor.nombre : null,
    id_tutor: tutor ? tutor.id_tutor : null,
    telegram_chat_id_tutor: tutor ? tutor.telegram_chat_id : null
  }
}];

const sesion = $('Router Paso').first().json;
const mensajeRaw = ($('Preparar Datos Entrada').first().json.mensaje || '').trim().toLowerCase();

let datos = {};
try { datos = JSON.parse(sesion.datos_parciales || '{}'); } catch (e) { datos = {}; }

// Cualquier respuesta que no sea 'si' se trata como cancelacion, para no dejar
// al estudiante atascado en este paso.
const confirma = (mensajeRaw === 'si' || mensajeRaw === 'si.' || mensajeRaw === 's\u00ed');

return [{
  json: {
    telegram_user: sesion.telegram_user,
    chat_id: sesion.telegram_user,
    materia: datos.materia || null,
    fecha: datos.fecha || null,
    id_tutoria: datos.id_tutoria || null,
    id_tutor: datos.id_tutor || null,
    id_dispo: datos.id_dispo || null,
    hora_inicio: datos.hora_inicio || null,
    tutor_nombre: datos.tutor_nombre || null,
    telegram_chat_id_tutor: datos.telegram_chat_id_tutor || null,
    confirma
  }
}];

const miUsuario = String($('Preparar Datos Entrada').first().json.telegram_user);
const propias = $input.all()
  .map(i => i.json)
  .filter(t => String(t.id_estudiante) === miUsuario);

let mensaje;
if (propias.length === 0) {
  mensaje = 'Aun no tienes tutorias registradas. Escribe INICIO para solicitar una.';
} else {
  mensaje = '\ud83d\udccb Tus tutorias:\n\n';
  propias.forEach(t => {
    mensaje += `\u2022 ${t.materia} - ${t.fecha}${t.hora ? ' ' + t.hora : ''} - Estado: ${t.estado}\n`;
  });
}

return [{ json: { telegram_user: miUsuario, mensaje } }];

const miUsuario = String($('Preparar Datos Entrada').first().json.telegram_user);
const activas = ['Solicitada', 'Asignada', 'Confirmada'];
const fila = $input.all()
  .map(i => i.json)
  .find(t => String(t.id_estudiante) === miUsuario && activas.includes(t.estado));

return [{
  json: {
    telegram_user: miUsuario,
    encontrada: !!fila,
    id_tutoria: fila ? fila.id_tutoria : null,
    id_dispo: fila ? fila.id_dispo : null,
    materia: fila ? fila.materia : null,
    fecha: fila ? fila.fecha : null
  }
}];

const hoy = new Date();
hoy.setHours(0,0,0,0);

const todas = $input.all().map(i => i.json);

const aFinalizar = todas.filter(t => {
  if (t.estado !== 'Confirmada') return false;
  const f = new Date(t.fecha);
  return !isNaN(f) && f < hoy;
});

return aFinalizar.map(t => ({
  json: { id_tutoria: t.id_tutoria, estado: 'Finalizada' }
}));

// 1. Tomamos los datos correctos que vienen del filtro por el cable
const todas = $input.all().map(i => i.json);

// 2. Contamos los estados de forma dinámica
const conteo = {};
for (const t of todas) {
  conteo[t.estado] = (conteo[t.estado] || 0) + 1;
}

// 3. Obtenemos la fecha de hoy en formato local YYYY-MM-DD
const hoy = new Date().toLocaleDateString('sv-SE'); 

// 4. Retornamos el formato que n8n necesita para la hoja de Google Sheets
return [{
  json: {
    fecha_reporte: hoy,
    total_tutorias: todas.length,
    solicitadas: conteo['Solicitada'] || 0,
    asignadas: conteo['Asignada'] || 0,
    confirmadas: conteo['Confirmada'] || 0,
    finalizadas: conteo['Finalizada'] || 0,
    canceladas: conteo['Cancelada'] || 0,
    sin_tutor: conteo['Sin_Tutor_Disponible'] || 0
  }
}];

// Recordatorios para tutorias CONFIRMADAS que ocurren manana
const tutorias = $('Leer Tutorias (Recordatorios)').all().map(i => i.json);
const tutores = $input.all().map(i => i.json);

const hoy = new Date(); hoy.setHours(0, 0, 0, 0);
const manana = new Date(hoy); manana.setDate(manana.getDate() + 1);
const mananaISO = manana.toISOString().slice(0, 10);

const aRecordar = tutorias.filter(t => t.estado === 'Confirmada' && t.fecha === mananaISO);

const items = [];
for (const t of aRecordar) {
  const tutor = tutores.find(tu => tu.id_tutor === t.id_tutor);
  const materia = t.materia;
  const hora = t.hora || 'hora por confirmar';
  const nombreTutor = tutor ? tutor.nombre : 'tu tutor';

  // Recordatorio para el estudiante
  items.push({
    json: {
      destino: 'estudiante',
      chat_id: t.id_estudiante,
      mensaje: `\u23F0 Recordatorio: manana tienes tutoria de ${materia} a las ${hora} con ${nombreTutor}.`
    }
  });

  // Recordatorio para el tutor (si tiene chat_id registrado)
  if (tutor && tutor.telegram_chat_id) {
    items.push({
      json: {
        destino: 'tutor',
        chat_id: tutor.telegram_chat_id,
        mensaje: `\u23F0 Recordatorio: manana tienes tutoria de ${materia} a las ${hora}.`
      }
    });
  }
}

return items;

// El offset ya NO se guarda en memoria de n8n (poco confiable con
// triggers de alta frecuencia, segun la propia documentacion de n8n).
// Ahora vive en la hoja "PollingState" de tu Google Sheet.
const token = $('Config Bot Token').first().json.bot_token;
const filas = $input.all().map(i => i.json);
const fila = filas[0];
const lastUpdateId = fila ? Number(fila.last_update_id || 0) : 0;
const offset = lastUpdateId ? lastUpdateId + 1 : 0;

return [{
  json: {
    url: `https://api.telegram.org/bot${token}/getUpdates?offset=${offset}&timeout=0`
  }
}];

const respuesta = $input.first().json;

if (!respuesta || respuesta.ok !== true || !Array.isArray(respuesta.result) || respuesta.result.length === 0) {
  return [{ json: { avanzarOffset: false, tieneMensaje: false } }];
}

// Procesamos SOLO el primer update pendiente por ciclo (uno a la vez,
// para no mezclar mensajes distintos en la misma ejecucion).
const primero = respuesta.result[0];

return [{
  json: {
    avanzarOffset: true,
    nuevoOffset: primero.update_id,
    tieneMensaje: !!primero.message,
    message: primero.message || null
  }
}];

// Arma un mensaje con los tutores y horarios libres para la materia elegida.
const materia = $('Guardar Materia Elegida').first().json.materia_elegida;
const telegram_user = $('Guardar Sesion Materia').first().json.telegram_user;

const tutores = $('Leer Tutores (Horarios)').all().map(i => i.json)
  .filter(t => t.estado === 'Activo' && (t.especialidad_materias || '').includes(materia));

const tutorIds = tutores.map(t => t.id_tutor);

const disponibilidad = $input.all().map(i => i.json)
  .filter(d => tutorIds.includes(d.id_tutor) && d.estado === 'Libre');

let mensaje;

if (disponibilidad.length === 0) {
  mensaje = `No hay horarios libres registrados por ahora para ${materia}. De todas formas puedes escribir una fecha y lo verificamos.`;
} else {
  // Agrupamos los horarios libres por tutor
  const porTutor = {};
  for (const d of disponibilidad) {
    const tutor = tutores.find(t => t.id_tutor === d.id_tutor);
    const nombre = tutor ? tutor.nombre : d.id_tutor;
    if (!porTutor[nombre]) porTutor[nombre] = [];
    porTutor[nombre].push(`${d.dia_semana} ${d.hora_inicio}-${d.hora_fin}`);
  }

  mensaje = `\ud83d\uddd3\ufe0f Tutores y horarios disponibles para ${materia}:\n\n`;
  for (const [nombre, horarios] of Object.entries(porTutor)) {
    mensaje += `\ud83d\udc64 ${nombre}: ${horarios.join(', ')}\n`;
  }
}

return [{ json: { telegram_user, mensaje } }];
